"use client";

import { useState, useEffect } from "react";
import { getWatchlist } from "@/lib/watchlist";
import type { WatchlistItem } from "@/types";
import Link from "next/link";
import { Star } from "lucide-react";
import LoadingSpinner from "@/components/ui/LoadingSpinner";

export default function WatchlistPage() {
  const [watchlist, setWatchlist] = useState<WatchlistItem[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getWatchlist()
      .then(setWatchlist)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <LoadingSpinner text="관심종목 불러오는 중..." />;

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold flex items-center gap-2">
        <Star className="w-6 h-6 text-amber-400" />
        내 관심종목
      </h1>

      {watchlist.length === 0 ? (
        <div className="bg-white/5 border border-white/10 rounded-xl p-8 text-center text-gray-400">
          <p className="text-lg mb-2">관심 종목이 없어요.</p>
          <p className="text-sm mb-4">종목 검색 후 상세 페이지에서 별 아이콘을 눌러 추가해 보세요.</p>
          <Link href="/stock" className="inline-block px-4 py-2 bg-skyblue/20 text-skyblue rounded-lg hover:bg-skyblue/30 transition-colors text-sm">
            종목 검색하러 가기
          </Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {watchlist.map((w) => (
            <Link
              key={w.id}
              href={`/stock/${w.stock_code}`}
              className="bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors flex items-center justify-between"
            >
              <div>
                <p className="font-medium">{w.stock_name}</p>
                <p className="text-xs text-gray-400 mt-0.5">{w.stock_code}</p>
              </div>
              <Star className="w-4 h-4 text-amber-400" />
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
